    const upgradedEdges = [];
    const remainingEdges = [];
    for (const [u, v, s] of optionalEdges) {
        if (upgradedEdges.length < k) {
            upgradedEdges.push([u, v, s * 2]);
        } else {
            remainingEdges.push([u, v, s]);
        }
    }

    const allEdges = [...mustEdges, ...upgradedEdges, ...remainingEdges];
    allEdges.sort((a, b) => b[2] - a[2]);

